const data = $input.first().json.body || $input.first().json || {};

let telefono = '';
let tipo = '';
let mediaId = '';
let mimeType = '';
let caption = '';

try {
  const entry = data.entry?.[0];
  const changes = entry?.changes?.[0];
  const value = changes?.value;
  if (value?.messages && value.messages.length > 0) {
    const message = value.messages[0];
    telefono = message.from || '';
    tipo = message.type || '';

    if (tipo === 'image') {
      mediaId = message.image?.id || '';
      mimeType = message.image?.mime_type || 'image/jpeg';
      caption = message.image?.caption || '';
    } else if (tipo === 'document') {
      mediaId = message.document?.id || '';
      mimeType = message.document?.mime_type || 'application/pdf';
      caption = message.document?.caption || '';
    }
    if (!caption) caption = message.text?.body || '';
  }
} catch(e) {
  // Fallback
  telefono = data.telefono || data.from || '';
  tipo = data.tipo || data.type || '';
}

// FIX PARA MÉXICO: WhatsApp Cloud API manda '521' pero requiere '52' para responder
if (telefono.startsWith('521') && telefono.length === 13) {
  telefono = telefono.replace(/^521/, '52');
}

const tieneDocumento = ['image', 'document'].includes(tipo) || mediaId !== '';
const capLower = caption.toLowerCase();

let tipoDoc = 'OTRO';
if (capLower.includes('ine') || capLower.includes('identificacion') || capLower.includes('credencial')) {
  tipoDoc = 'INE';
} else if (capLower.includes('domicilio') || capLower.includes('cfe') || capLower.includes('comprobante') || capLower.includes('luz') || capLower.includes('agua')) {
  tipoDoc = 'COMPROBANTE_DOMICILIO';
} else if (capLower.includes('pension') || capLower.includes('imss') || capLower.includes('resolucion') || capLower.includes('amarilla')) {
  tipoDoc = 'RESOLUCION_PENSION';
} else if (capLower.includes('resumen') || capLower.includes('movimientos')) {
  tipoDoc = 'RESUMEN_MOVIMIENTOS';
} else if (capLower.includes('estado') || capLower.includes('cuenta') || capLower.includes('banco')) {
  tipoDoc = 'ESTADO_CUENTA';
} else if (capLower.includes('foto') || capLower.includes('selfie') || capLower.includes('sosteniendo')) {
  tipoDoc = 'FOTO_INE';
}

// Si logramos extraer aunque sea el mediaId pero no el tipo, forzamos que tiene documento
return [{ json: { telefono, mediaId, mimeType, tipoDoc, caption, tieneDocumento, rawTipo: tipo } }];

// ================================================================
// Registrar incidencia en Base de Incidencias (Proforma V4.1 §7.4)
// El rechazo debe ser ESPECÍFICO por documento, nunca genérico.
// ================================================================
const resultado = $input.first().json;
const tipoDoc = $('Identificar Tipo de Documento').item.json.tipoDoc;
const telefono = $('Identificar Tipo de Documento').item.json.telefono;

// Construir nombre legible del documento
const nombresDoc = {
  'INE': 'INE',
  'COMPROBANTE_DOMICILIO': 'Comprobante de Domicilio',
  'RESOLUCION_PENSION': 'Resolución de Pensión',
  'ESTADO_CUENTA': 'Estado de Cuenta',
  'RESUMEN_MOVIMIENTOS': 'Resumen de Movimientos',
  'FOTO_INE': 'Foto con INE',
  'OTRO': 'Documento'
};

const nombreLegible = nombresDoc[tipoDoc] || tipoDoc;

// El mensaje de rechazo viene del backend (ya es específico)
const motivoDetallado = resultado.observaciones || 'No se pudo determinar el motivo del rechazo';

return [{ json: {
  telefono,
  tipoDoc,
  nombreLegible,
  motivoDetallado,
  puntajeCalidad: resultado.puntajeCalidad || 0,
  timestamp: new Date().toISOString()
} }];

